@@ -1112,6 +1112,35 @@ child.getClass().getName(), propName, OverwriteMode.NULLS);

     protected boolean _childrenEqual(ObjectNode other) {
+        // Compare entries in iteration order so that two ObjectNodes with identical
+        // keys and values but different field ordering are considered unequal.
+        if (_children.size() != other._children.size()) {
+            return false;
+        }
+        Iterator<Map.Entry<String, JsonNode>> it1 = _children.entrySet().iterator();
+        Iterator<Map.Entry<String, JsonNode>> it2 = other._children.entrySet().iterator();
+        while (it1.hasNext()) {
+            Map.Entry<String, JsonNode> e1 = it1.next();
+            Map.Entry<String, JsonNode> e2 = it2.next();
+            if (!e1.getKey().equals(e2.getKey()) || !e1.getValue().equals(e2.getValue())) {
+                return false;
+            }
+        }
+        return true;
+    }
+
+    /**
+     * Equality check that ignores field ordering: returns true if both
+     * nodes have the same set of properties with equal values, regardless of the
+     * order in which properties were inserted. This is the pre-3.x semantics
+     * of equals(Object).
+     *
+     * @param other ObjectNode to compare against (may be null)
+     * @return true if both nodes have the same properties ignoring order
+     */
+    public boolean equalsIgnoreOrder(ObjectNode other) {
+        if (other == this) return true;
+        if (other == null) return false;
         return _children.equals(other._children);
     }
